INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b63077dc-bfe3-41ed-8d98-8b7948d79aa6',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAPI to GraphQL — Schema Design, Resolvers, N+1, and DataLoader Explained$escape$,
  $escape$Coming from OpenAPI, the mental shift to GraphQL starts at the schema. Where OpenAPI defines discrete paths with request/response shapes, GraphQL has a single typed schema as the contract — `type Query`, `type Mutation`, `type Subscription`. Each field maps to a resolver function, not a controller action. The N+1 problem hits hard when resolvers are naïve: fetching a list of `Post` objects then firing a separate DB query per `author` field — 1 list query + N author queries. DataLoader solves this by batching and caching: it collects all author IDs requested within a single event-loop tick, then fires one batched query. Unlike OpenAPI's polling or SSE patterns, GraphQL subscriptions use WebSocket transport via `graphql-ws`, with `subscribe` resolvers yielding async iterables. Schema-first design (SDL) is the OpenAPI equivalent of writing your spec first — define types, then wire resolvers. Use `graphql-tag` for query parsing and `@defer`/`@stream` directives for incremental delivery, which have no direct OpenAPI analogue.$escape$,
  $escape$import DataLoader from 'dataloader';
import { GraphQLResolveInfo } from 'graphql';

const userLoader = new DataLoader<string, User>(async (ids) => {
  const users = await db.query(
    'SELECT * FROM users WHERE id = ANY($1)', [ids]
  );
  return ids.map(id => users.find(u => u.id === id));
});

export const resolvers = {
  Post: {
    author: (post: Post) => userLoader.load(post.authorId),
  },
  Subscription: {
    postCreated: {
      subscribe: () => pubSub.asyncIterator(['POST_CREATED']),
    },
  },
};$escape$,
