INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9850960c-a72a-405a-aad2-08fd99bc43ec',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAPI Security Schemes — Defining OAuth2, JWT, API Keys, and mTLS in Your Spec$escape$,
  $escape$OpenAPI 3.x centralizes auth definitions under `components/securitySchemes`, keeping your security contracts machine-readable and tooling-friendly. For JWT in headers, use `type: http` with `scheme: bearer` and `bearerFormat: JWT` — this signals to generators (Swagger UI, Speakeasy) to inject `Authorization: Bearer <token>`. API keys use `type: apiKey` with `in: header|query|cookie` and a `name` field matching the exact header or param. OAuth2 schemes declare the full flow: `authorizationUrl`, `tokenUrl`, and fine-grained `scopes` per flow (e.g., `clientCredentials`, `authorizationCode`). Apply them globally or per-operation via the `security` array, using an empty `security: []` on an operation to explicitly mark it public — don't rely on omission. For mTLS, OpenAPI 3.1 added `type: mutualTLS`, which signals certificate-based auth without encoding cert details in the spec itself. Combining schemes in a single `security` entry means AND logic; multiple entries mean OR. Scope enforcement and actual validation remain in your gateway or middleware — the spec is the contract, not the enforcer.$escape$,
  $escape$components:
  securitySchemes:
    BearerAuth:
      type: http
      scheme: bearer
      bearerFormat: JWT
    ApiKeyAuth:
      type: apiKey
      in: header
      name: X-API-Key
    OAuth2CC:
      type: oauth2
      flows:
        clientCredentials:
          tokenUrl: https://auth.example.com/token
          scopes:
            read:bytes: Read byte content
            write:bytes: Publish bytes
    MtlsAuth:
      type: mutualTLS

security:
  - BearerAuth: []

paths:
  /bytes:
    post:
      security:
        - OAuth2CC: [write:bytes]
        - ApiKeyAuth: []
  /public/feed:
    get:
      security: []$escape$,
  $escape$bash$escape$,
