INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'af714169-9f65-4efb-884a-9a77f402aa09',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAPI WebSockets — Lifecycle, Heartbeat, and Rooms Alongside Your REST Spec$escape$,
  $escape$OpenAPI 3.x models HTTP semantics only — WebSocket connections sit outside the spec entirely. The upgrade handshake (`HTTP 101 Switching Protocols`) is the only touchpoint OpenAPI can describe. Annotate your upgrade path in your OpenAPI YAML with `x-websocket: true` and `x-channels` to enumerate room patterns (`/ws/rooms/{roomId}`), making the contract discoverable in Swagger UI even though it can't execute WebSocket calls.

At runtime, three patterns matter: heartbeat, reconnection, and rooms. Use `ws.ping()` every 30s and terminate on missed pong — the `ws` library fires `pong` events automatically. For reconnection, exponential backoff with jitter (`delay = base * 2^attempt + rand(0, 1000)ms`) prevents thundering herd after a server restart. Rooms map cleanly to dynamic channels: store a `Map<roomId, Set<WebSocket>>` server-side and broadcast with a simple loop.

In OpenAPI 3.1, document the `101` response on your `/ws` path with `x-websocket-channels` listing all room patterns. Pair this with an AsyncAPI 3.0 spec for full event schema coverage — OpenAPI owns the upgrade contract, AsyncAPI owns the message payloads.$escape$,
  $escape$import { WebSocketServer, WebSocket } from 'ws';
const rooms = new Map<string, Set<WebSocket>>();
const wss = new WebSocketServer({ port: 8080 });

wss.on('connection', (ws: WebSocket) => {
  let alive = true;
  ws.on('pong', () => { alive = true; });
  const hb = setInterval(() => { if (!alive) return ws.terminate(); alive = false; ws.ping(); }, 30_000);
  ws.on('message', (raw) => {
    const { type, room } = JSON.parse(raw.toString());
    if (type === 'join') { if (!rooms.has(room)) rooms.set(room, new Set()); rooms.get(room)!.add(ws); }
  });
  ws.on('close', () => clearInterval(hb));
});$escape$,
  $escape$typescript$escape$,
